        .eol_a => {
            const ok = pos == input.len or (re.flags.multiline and pos < input.len and input[pos] == '\n');
            if (ok) try _re_eclosure_s(re, cur, vis, alloc, nd.out1, saves, pos, input);
        },
        .wb => {
